<template><div class="auth-page"><el-card class="auth-box"><h2>登录 Taffy</h2><el-form :model="form" @keyup.enter="submit"><el-form-item><el-input v-model="form.username" placeholder="用户名"/></el-form-item><el-form-item><el-input v-model="form.password" type="password" show-password placeholder="密码"/></el-form-item><el-button class="full" type="primary" :loading="loading" @click="submit">登录</el-button><p class="muted">还没有账号？<router-link to="/register">去注册</router-link></p></el-form></el-card></div></template>
<script setup>import { reactive,ref } from 'vue';import { useRouter } from 'vue-router';import { ElMessage } from 'element-plus';import { useUserStore } from '../stores/user';const router=useRouter(),store=useUserStore(),loading=ref(false);const form=reactive({username:'',password:''});async function submit(){if(!form.username||!form.password)return ElMessage.warning('请输入用户名和密码');loading.value=true;try{await store.doLogin(form);ElMessage.success('登录成功');router.push('/dashboard')}finally{loading.value=false}}</script>
